    starter: "class KVCache:\n    def __init__(self, max_len):\n        # TODO\n        raise NotImplementedError\n\n    def append(self, k, v):\n        raise NotImplementedError\n\n    def get(self):\n        raise NotImplementedError\n\n    def __len__(self):\n        raise NotImplementedError\n",
    solution: "from collections import deque\n\nclass KVCache:\n    def __init__(self, max_len):\n        self.max_len = max_len\n        self._k = deque()\n        self._v = deque()\n\n    def append(self, k, v):\n        self._k.append(k)\n        self._v.append(v)\n        while len(self._k) > self.max_len:\n            self._k.popleft()\n            self._v.popleft()\n\n    def get(self):\n        return list(self._k), list(self._v)\n\n    def __len__(self):\n        return len(self._k)\n",
