      solution: "from collections import deque\n\nclass KVCache:\n    def __init__(self, max_len, max_bytes=None):\n        self.max_len = max_len\n        self.max_bytes = max_bytes\n        self._q = deque()  # (k, v, nbytes)\n        self._bytes = 0\n\n    def append(self, k, v, nbytes=0):\n        self._q.append((k, v, nbytes))\n        self._bytes += nbytes\n        while len(self._q) > self.max_len or (self.max_bytes is not None and self._bytes > self.max_bytes):\n            _, _, b = self._q.popleft()\n            self._bytes -= b\n\n    def get(self):\n        return [x[0] for x in self._q], [x[1] for x in self._q]\n\n    def total_bytes(self):\n        return self._bytes\n\n    def __len__(self):\n        return len(self._q)\n",
