    starter: "def compact(messages, budget, count_tokens, summarize):\n    # TODO: keep system + recent tail; summarize the dropped middle; respect the budget.\n    raise NotImplementedError\n",
    solution: "def compact(messages, budget, count_tokens, summarize):\n    cost = lambda m: count_tokens(m['content'])\n    if sum(cost(m) for m in messages) <= budget:\n        return list(messages)\n    has_system = bool(messages) and messages[0]['role'] == 'system'\n    system = [messages[0]] if has_system else []\n    body = messages[1:] if has_system else list(messages)\n    base = sum(cost(m) for m in system)\n    # try progressively shorter tails until (system + summary + tail) fits\n    for start in range(len(body)):\n        dropped, tail = body[:start] if False else body[:len(body)], []\n    n = len(body)\n    for keep in range(n, -1, -1):\n        tail = body[n - keep:]\n        dropped = body[:n - keep]\n        summary_msg = None\n        total = base + sum(cost(m) for m in tail)\n        if dropped:\n            summary_msg = {'role': 'system', 'content': '[Summary] ' + summarize(dropped)}\n            total += cost(summary_msg)\n        if total <= budget:\n            return system + ([summary_msg] if summary_msg else []) + tail\n    # nothing fits: system + summary of everything\n    summary_msg = {'role': 'system', 'content': '[Summary] ' + summarize(body)}\n    return system + [summary_msg]\n",
