    starter: "class TokenBucket:\n    def __init__(self, rate, capacity, now_fn):\n        # TODO: start full; refill lazily from elapsed time in allow().\n        raise NotImplementedError\n\n    def allow(self, n=1):\n        raise NotImplementedError\n",
    solution: "class TokenBucket:\n    def __init__(self, rate, capacity, now_fn):\n        self.rate = rate\n        self.capacity = capacity\n        self.now_fn = now_fn\n        self.tokens = float(capacity)\n        self.last = now_fn()\n\n    def _refill(self):\n        now = self.now_fn()\n        elapsed = max(0.0, now - self.last)\n        self.last = now\n        self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)\n\n    def allow(self, n=1):\n        self._refill()\n        if self.tokens >= n:\n            self.tokens -= n\n            return True\n        return False\n",
